useEffect(() => {
  // Setup: acquire a resource
  const subscription = store.subscribe(handleChange);

  // Cleanup: release the resource
  // This runs before unmount AND before the next setup when deps change
  return () => {
    subscription.unsubscribe();
  };
}, [store]);

// Cleanup and setup sequence when roomId changes:
// 1. useEffect cleanup: disconnect from roomId="A"
// 2. useEffect setup: connect to roomId="B"
// Same cleanup function, called with the captured closure from the previous run

function ChatRoom({ roomId }) {
  useEffect(() => {
    const socket = connectToRoom(roomId);
    return () => socket.disconnect(); // captures roomId from closure
  }, [roomId]);
}

// In StrictMode development:
// Mount sequence → mount → unmount → remount
// This simulates a real-world pattern where a component is conditionally rendered

// Log sequence in development:
// [SETUP] roomId=A    ← first mount
// [CLEANUP] roomId=A  ← StrictMode unmount (cleanup called)
// [SETUP] roomId=A    ← StrictMode remount

// Your setup must be safe to run twice with a cleanup in between
function ChatRoom({ roomId }) {
  useEffect(() => {
    console.log('[SETUP] roomId=' + roomId);
    const socket = connectToRoom(roomId);
    return () => {
      console.log('[CLEANUP] roomId=' + roomId);
      socket.disconnect();
    };
  }, [roomId]);
}

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const controller = new AbortController();

    fetch(`/api/users/${userId}`, { signal: controller.signal })
      .then((res) => res.json())
      .then((data) => setUser(data))
      .catch((err) => {
        if (err.name === 'AbortError') return; // expected cancellation
        console.error('Fetch failed:', err);
      });

    // Cleanup: abort the in-flight request on unmount or userId change
    return () => controller.abort();
  }, [userId]);

  if (!user) return <p>Loading…</p>;
  return <h1>{user.name}</h1>;
}

// setInterval example
function Countdown({ seconds }) {
  const [remaining, setRemaining] = useState(seconds);

  useEffect(() => {
    if (remaining <= 0) return; // no resource to clean up

    const id = setInterval(() => {
      setRemaining((r) => r - 1);
    }, 1000);

    // Cleanup: clear the interval when component unmounts or seconds changes
    return () => clearInterval(id);
  }, [seconds, remaining]);

  return <p>{remaining}s remaining</p>;
}

// setTimeout example — single-fire after delay
function Toast({ message, onDismiss }) {
  useEffect(() => {
    const id = setTimeout(onDismiss, 3000);
    return () => clearTimeout(id); // prevents dismiss after unmount
  }, [onDismiss]);

  return <div className="toast">{message}</div>;
}

function KeyboardShortcut({ onSave }) {
  useEffect(() => {
    function handleKeyDown(e) {
      if (e.key === 's' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        onSave();
      }
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onSave]); // onSave is in deps — update cleanup + setup when it changes

  return null;
}

// IntersectionObserver — detect when element enters viewport
function LazyImage({ src, alt }) {
  const imgRef = useRef(null);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    const el = imgRef.current;
    if (!el) return;

    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setLoaded(true);
        observer.unobserve(el); // once loaded, stop watching
      }
    });

    observer.observe(el);
    return () => observer.disconnect(); // cleanup on unmount
  }, []);

  return (
    <img
      ref={imgRef}
      src={loaded ? src : undefined}
      alt={alt}
    />
  );
}

// ResizeObserver — track element size
function useElementSize(ref) {
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new ResizeObserver(([entry]) => {
      setSize({ width: entry.contentRect.width, height: entry.contentRect.height });
    });

    observer.observe(el);
    return () => observer.disconnect();
  }, [ref]);

  return size;
}

import { render, act } from '@testing-library/react';

test('clears interval on unmount', () => {
  jest.useFakeTimers();
  const clearIntervalSpy = jest.spyOn(global, 'clearInterval');

  const { unmount } = render(<Countdown seconds={10} />);
  unmount();

  expect(clearIntervalSpy).toHaveBeenCalled();
  jest.useRealTimers();
  clearIntervalSpy.mockRestore();
});

test('aborts fetch on unmount', () => {
  const abortSpy = jest.fn();
  global.AbortController = jest.fn(() => ({
    signal: {},
    abort: abortSpy,
  }));

  const { unmount } = render(<UserProfile userId="1" />);
  unmount();

  expect(abortSpy).toHaveBeenCalled();
});

// Chart.js integration
import { useEffect, useRef } from 'react';
import Chart from 'chart.js/auto';

function BarChart({ data }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const chart = new Chart(canvasRef.current, {
      type: 'bar',
      data,
    });

    // Destroy the chart instance on unmount to release its canvas
    return () => chart.destroy();
  }, [data]);

  return <canvas ref={canvasRef} />;
}

// Manual exit animation with cleanup
function AnimatedPanel({ visible }) {
  const [mounted, setMounted] = useState(visible);
  const [animating, setAnimating] = useState(false);

  useEffect(() => {
    if (visible) {
      setMounted(true);
      setAnimating(true);
    } else {
      setAnimating(false);
      // Remove from DOM after animation completes
      const id = setTimeout(() => setMounted(false), 300);
      return () => clearTimeout(id);
    }
  }, [visible]);

  if (!mounted) return null;
  return (
    <div style={{ opacity: animating ? 1 : 0, transition: 'opacity 300ms' }}>
      content
    </div>
  );
}

// Data fetching with Suspense
function Profile({ userId }) {
  // If fetchUser suspends, React unmounts Profile and runs cleanup
  const user = use(fetchUser(userId));

  useEffect(() => {
    analytics.track('profile-viewed', { userId });
    return () => analytics.track('profile-closed', { userId });
  }, [userId]);

  return <h1>{user.name}</h1>;
}

import { createPortal } from 'react-dom';

function Modal({ onClose, children }) {
  // Effect inside the modal follows the modal's lifecycle
  useEffect(() => {
    function handleKey(e) {
      if (e.key === 'Escape') onClose();
    }
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [onClose]);

  // Renders inside document.body but lifecycle is tied to Modal's parent
  return createPortal(
    <div className="modal-overlay">
      <div className="modal-content">{children}</div>
    </div>,
    document.body
  );
}
